mapper.select:
SELECT c.id, c.name, c.type, COUNT(CASE WHEN c.type = 1 THEN d.id END) AS dish_count FROM category c LEFT JOIN dish d ON c.id = d.category_id AND d.status = 1 WHERE c.merchant_id = #{merchantId} AND c.status = 1
AND c.type = #{type}
GROUP BY c.id, c.name, c.type ORDER BY c.sort ASC, c.create_time DESC
